236	func intakeResultPayload(result *Result) (string, error) {
237		if result == nil {
238			return "", fmt.Errorf("pre-claim intake: empty runner result")
239		}
240		text := strings.TrimSpace(result.CondensedOutput)
241		if text == "" {
242			text = strings.TrimSpace(result.Output)
243		}
244		if text == "" {
245			if strings.TrimSpace(result.Error) != "" {
246				return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
247			}
248			if result.ExitCode != 0 {
249				return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
250			}
251			return "", fmt.Errorf("pre-claim intake: empty output")
252		}
253		candidate, ok := extractJSONCandidate(text)
254		if !ok {
255			return "", fmt.Errorf("pre-claim intake: no JSON object found")
256		}
257		return candidate, nil
258	}
