86	// ComplexityGuard delegates to an injected complexity gate. When no gate is
87	// configured it allows the bead to proceed. The model-backed pre-claim intake
88	// hook is now the canonical readiness gate; this compatibility wrapper remains
89	// only for older callers that still inject a Guard directly.
90	type ComplexityGuard struct {
91		Gate Guard
92		Log  io.Writer
93	
94		once sync.Once
95	}
96	
97	// NewComplexityGuard wraps the configured gate.
98	func NewComplexityGuard(gate Guard, log io.Writer) *ComplexityGuard {
99		return &ComplexityGuard{Gate: gate, Log: log}
100	}
101	
102	// Allow either delegates to the configured gate or fail-opens silently when the
103	// gate is absent.
104	func (g *ComplexityGuard) Allow(ctx context.Context, beadID string) (bool, string) {
105		if g == nil || g.Gate == nil {
106			return true, ""
107		}
108		return g.Gate.Allow(ctx, beadID)
109	}
