		ProjectRoot: root,
		Harness:     "claude",
		Mode:        "once",
		NoReview:    true,
	})
	require.NoError(t, err)
	_ = waitForWorkerExit(t, m, record.ID, 10*time.Second)

	// AC2: worker log must contain actionable readiness-unavailable evidence.
